// DashboardScreen.jsx — The full dashboard view

import ChartCard from "./ChartCard";
import InsightPanel from "./InsightPanel";
import VoicePanel from "./VoicePanel";

export default function DashboardScreen({ data, sessionId, colorSchema, onReset }) {
  const { dashboard_title, charts, insights, summary, kpi_coverage, total_kpis_generated } = data;

  // Build context for voice Q&A
  const voiceContext = charts.map((c) => ({
    kpi: c.kpi,
    chart_type: c.chart_type,
    data: c.data.slice(0, 20),
  }));

  return (
    <div style={styles.screen}>
      {/* Top bar */}
      <div style={styles.topBar}>
        <div style={styles.topLeft}>
          <div style={styles.logoMini}>
            <svg width="18" height="18" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="13" stroke="#4f8ef7" strokeWidth="1.5"/>
              <path d="M8 18 L12 10 L16 15 L20 8" stroke="#4f8ef7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="8" r="2" fill="#7c5cfc"/>
            </svg>
          </div>
          <div>
            <h1 style={styles.dashTitle}>{dashboard_title}</h1>
          </div>
        </div>

        {/* Stats */}
        <div style={styles.statRow}>
          <div style={styles.stat}>
            <span style={styles.statNum}>{total_kpis_generated}</span>
            <span style={styles.statLabel}>Charts</span>
          </div>
          <div style={styles.statDivider} />
          <div style={styles.stat}>
            <span style={{ ...styles.statNum, color: kpi_coverage >= 80 ? "var(--success)" : "var(--warn)" }}>
              {kpi_coverage}%
            </span>
            <span style={styles.statLabel}>KPI Coverage</span>
          </div>
          <div style={styles.statDivider} />
          <button style={styles.resetBtn} onClick={onReset}>
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
              <path d="M2 7a5 5 0 015-5 5 5 0 014.9 4M12 2v4H8" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/>
            </svg>
            New Dashboard
          </button>
        </div>
      </div>

      {/* Body */}
      <div style={styles.body}>
        {/* Charts grid */}
        <div style={styles.mainCol}>
          <div style={styles.chartsGrid}>
            {charts.map((chart, i) => (
              <ChartCard
                key={chart.kpi}
                chart={chart}
                colorSchema={colorSchema}
                index={i}
              />
            ))}
          </div>
        </div>

        {/* Right sidebar */}
        <div style={styles.sideCol}>
          <VoicePanel
            sessionId={sessionId}
            dashboardContext={voiceContext}
          />
          <InsightPanel
            insights={insights}
            summary={summary}
          />
        </div>
      </div>
    </div>
  );
}

const styles = {
  screen: { minHeight: "100vh", display: "flex", flexDirection: "column" },
  topBar: {
    padding: "14px 28px",
    borderBottom: "1px solid var(--border)",
    display: "flex", alignItems: "center", justifyContent: "space-between",
    background: "rgba(10,12,16,0.95)",
    backdropFilter: "blur(12px)",
    position: "sticky", top: 0, zIndex: 10,
  },
  topLeft: { display: "flex", alignItems: "center", gap: "12px" },
  logoMini: {
    width: "34px", height: "34px",
    background: "rgba(79,142,247,0.1)", border: "1px solid rgba(79,142,247,0.2)",
    borderRadius: "10px", display: "flex", alignItems: "center", justifyContent: "center",
  },
  dashTitle: {
    fontSize: "18px", fontWeight: 800, color: "#fff", letterSpacing: "-0.3px",
  },
  statRow: { display: "flex", alignItems: "center", gap: "20px" },
  stat: { display: "flex", flexDirection: "column", alignItems: "center", gap: "2px" },
  statNum: { fontSize: "18px", fontWeight: 800, color: "var(--accent)", fontFamily: "'Syne', sans-serif" },
  statLabel: { fontSize: "10px", color: "var(--text3)", textTransform: "uppercase", letterSpacing: "0.07em" },
  statDivider: { width: "1px", height: "32px", background: "var(--border)" },
  resetBtn: {
    display: "flex", alignItems: "center", gap: "6px",
    padding: "8px 16px",
    background: "var(--bg3)", border: "1px solid var(--border2)",
    borderRadius: "var(--radius)", color: "var(--text2)",
    fontSize: "13px", cursor: "pointer", transition: "all 0.15s",
  },
  body: {
    flex: 1, display: "flex", gap: 0,
    overflow: "hidden",
  },
  mainCol: {
    flex: 1, overflowY: "auto", padding: "24px",
  },
  chartsGrid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fill, minmax(440px, 1fr))",
    gap: "20px",
  },
  sideCol: {
    width: "380px", borderLeft: "1px solid var(--border)",
    overflowY: "auto", padding: "20px",
    display: "flex", flexDirection: "column", gap: "20px",
    background: "var(--bg2)",
  },
};
